// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.ArrayList;
import java.util.List;

import org.eclipse.rdf4j.sail.lmdb.TxnManager.Txn;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Storage-level tests for {@link RecordIterator#seekForward}: repositioning a range scan forward with one
 * {@code MDB_SET_RANGE} while range clamping and match filtering stay intact.
 */
public class LmdbRecordIteratorSeekTest {

	@TempDir
	File dataDir;

	private TripleStore tripleStore;

	@BeforeEach
	public void setUp() throws Exception {
		tripleStore = new TripleStore(dataDir, new LmdbStoreConfig("spoc,posc"), null);
		tripleStore.startTransaction();
		for (long subj = 100; subj < 110; subj++) {
			tripleStore.storeTriple(subj, 10, 1000 + subj, 1, true);
		}
		tripleStore.commit();
	}

	@Test
	public void seekForwardSkipsToTargetSubject() throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			// full scan over predicate 10 in posc order: subjects 100..109 ascending
			try (RecordIterator iterator = tripleStore.getTriples(txn, -1, 10, -1, -1, true)) {
				long[] first = iterator.next();
				assertThat(first).isNotNull();
				assertThat(first[TripleIndex.SUBJ_IDX]).isEqualTo(100L);

				// seek forward: next record must be the first with object >= 1106 (subject 106)
				assertThat(iterator.seekForward(0, 10, 1106, 0)).isTrue();
				long[] afterSeek = iterator.next();
				assertThat(afterSeek).isNotNull();
				assertThat(afterSeek[TripleIndex.SUBJ_IDX]).isEqualTo(106L);

				// iteration continues normally from there
				List<Long> rest = new ArrayList<>();
				long[] quad;
				while ((quad = iterator.next()) != null) {
					rest.add(quad[TripleIndex.SUBJ_IDX]);
				}
				assertThat(rest).containsExactly(107L, 108L, 109L);
			}
		}
	}

	@Test
	public void seekForwardBeyondRangeExhaustsIterator() throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			try (RecordIterator iterator = tripleStore.getTriples(txn, -1, 10, -1, -1, true)) {
				assertThat(iterator.next()).isNotNull();
				// no object beyond 2000 exists under predicate 10: the range filter must terminate the scan
				assertThat(iterator.seekForward(0, 10, 999_999, 0)).isTrue();
				assertThat(iterator.next()).isNull();
			}
		}
	}

	@Test
	public void seekForwardOnExhaustedIteratorReturnsFalse() throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			try (RecordIterator iterator = tripleStore.getTriples(txn, -1, 10, -1, -1, true)) {
				while (iterator.next() != null) {
					// drain
				}
				assertThat(iterator.seekForward(0, 10, 1106, 0)).isFalse();
			}
		}
	}

	@Test
	public void seekForwardComposesWithFillBatches() throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			try (RecordIterator iterator = tripleStore.getTriples(txn, -1, 10, -1, -1, true)) {
				long[] buffer = new long[4 * 4];
				assertThat(iterator.fill(buffer, 4)).isEqualTo(4);
				assertThat(iterator.seekForward(0, 10, 1108, 0)).isTrue();
				int rows = iterator.fill(buffer, 4);
				assertThat(rows).isEqualTo(2);
				assertThat(buffer[TripleIndex.SUBJ_IDX]).isEqualTo(108L);
				assertThat(buffer[4 + TripleIndex.SUBJ_IDX]).isEqualTo(109L);
			}
		}
	}
}
